import { Metadata } from 'next';
import { notFound } from 'next/navigation';
import { projects } from '@/data/projects';
import Link from 'next/link';
import { sanitizeHtml } from '@/utils/sanitize';
import { logger } from '@/utils/logger';
import Header from '@/components/Header/Header';
import './project.css';

// Función adaptadora para convertir proyecto de BD a formato esperado
function adaptDBProject(dbProject: any) {
    return {
        slug: dbProject.slug,
        title: {
            es: dbProject.title,
            en: dbProject.title
        },
        description: {
            es: dbProject.portfolioData?.shortDescription || '',
            en: dbProject.portfolioData?.shortDescription || ''
        },
        longDescription: {
            es: dbProject.blocks || '',
            en: dbProject.blocks || ''
        },
        client: dbProject.portfolioData?.client || 'Cliente',
        industry: dbProject.category || 'Industria',
        year: new Date(dbProject.createdAt).getFullYear(),
        tags: dbProject.seo?.keywords?.split(',').map((k: string) => k.trim()) || [],
        images: {
            hero: dbProject.portfolioData?.heroImage || '/img/placeholder.png',
            gallery: dbProject.portfolioData?.gallery || []
        },
        results: dbProject.portfolioData?.results?.map((r: any) => ({
            value: r.value + (r.unit || ''),
            metric: r.metric,
            description: {
                es: r.label,
                en: r.label
            }
        })) || [],
        technologies: dbProject.portfolioData?.technologies?.map((t: any) => t.name) || [],
        seo: {
            metaTitle: {
                es: dbProject.seo?.metaTitle || dbProject.title,
                en: dbProject.seo?.metaTitle || dbProject.title
            },
            metaDescription: {
                es: dbProject.seo?.metaDescription || dbProject.portfolioData?.shortDescription || '',
                en: dbProject.seo?.metaDescription || dbProject.portfolioData?.shortDescription || ''
            },
            keywords: dbProject.seo?.keywords?.split(',') || [],
            ogImage: dbProject.portfolioData?.heroImage || '/img/placeholder.png'
        }
    };
}

// Generar rutas estáticas en build time
export async function generateStaticParams() {
    return projects.map((project) => ({
        slug: project.slug,
    }));
}

// Metadata dinámica para SEO
export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    const { slug } = await params;

    // Intentar cargar desde BD primero
    let project = null;
    try {
        const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';
        const res = await fetch(`${API_URL}/content/slug/${slug}`, {
            cache: 'no-store'
        });

        if (res.ok) {
            const dbProject = await res.json();
            project = adaptDBProject(dbProject);
        }
    } catch (error) {
        logger.error('Failed to load project from API', error, 'generateMetadata');
    }

    // Fallback a proyectos hardcoded
    if (!project) {
        project = projects.find(p => p.slug === slug);
    }

    if (!project) return {};

    return {
        title: project.seo.metaTitle.es,
        description: project.seo.metaDescription.es,
        keywords: project.seo.keywords,
        openGraph: {
            title: project.seo.metaTitle.es,
            description: project.seo.metaDescription.es,
            images: [project.images.hero],
            type: 'article',
        },
        twitter: {
            card: 'summary_large_image',
            title: project.seo.metaTitle.es,
            description: project.seo.metaDescription.es,
            images: [project.images.hero],
        },
        alternates: {
            canonical: `https://josegaspard.dev/portafolio/${slug}`,
        },
    };
}

export default async function ProjectPage({ params }: { params: Promise<{ slug: string }> }) {
    const { slug } = await params;

    // Intentar cargar desde BD primero
    let project = null;
    let isFromDB = false;

    try {
        const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';
        const res = await fetch(`${API_URL}/content/slug/${slug}`, {
            cache: 'no-store'
        });

        if (res.ok) {
            const dbProject = await res.json();
            project = adaptDBProject(dbProject);
            isFromDB = true;
        }
    } catch (error) {
        logger.error('Failed to load project from API', error, 'ProjectPage');
    }

    // Fallback a proyectos hardcoded si no se encuentra en BD
    if (!project) {
        project = projects.find(p => p.slug === slug);
    }

    if (!project) {
        notFound();
    }

    // Schema.org JSON-LD para SEO
    const jsonLd = {
        '@context': 'https://schema.org',
        '@type': 'CreativeWork',
        name: project.title.es,
        description: project.description.es,
        author: {
            '@type': 'Person',
            name: 'José Gaspard',
            url: 'https://josegaspard.dev',
            jobTitle: 'SEO Architect & Full-Stack Developer',
        },
        datePublished: `${project.year}-01-01`,
        image: project.images.hero,
        keywords: project.tags.join(', '),
        about: {
            '@type': 'Thing',
            name: project.industry,
        },
    };

    return (
        <>
            <Header />
            <script
                type="application/ld+json"
                dangerouslySetInnerHTML={{ __html: sanitizeHtml(JSON.stringify(jsonLd)) }}
            />

            <main className="project-detail-page">
                {/* Hero Section */}
                <section className="project-hero" style={{ backgroundImage: `url(${project.images.hero})` }}>
                    <div className="project-hero-overlay"></div>
                    <div className="container project-hero-content">
                        <Link href="/portafolio" className="back-link">
                            ← Volver al Portafolio
                        </Link>
                        <div className="project-tags">
                            {project.tags.map((tag: string, i: number) => (
                                <span key={i} className="tag">{tag}</span>
                            ))}
                        </div>
                        <h1 className="project-hero-title">{project.title.es}</h1>
                        <p className="project-hero-description">{project.description.es}</p>
                        <div className="project-hero-meta">
                            <span><strong>Cliente:</strong> {project.client}</span>
                            <span><strong>Industria:</strong> {project.industry}</span>
                            <span><strong>Año:</strong> {project.year}</span>
                        </div>
                        {isFromDB && (
                            <div className="db-badge">
                                <i className="fas fa-database"></i> Proyecto Dinámico
                            </div>
                        )}
                    </div>
                </section>

                {/* Results Section */}
                {project.results && project.results.length > 0 && (
                    <section className="project-results section">
                        <div className="container">
                            <h2 className="section-title">Resultados Clave</h2>
                            <div className="results-grid">
                                {project.results.map((result: any, i: number) => (
                                    <div key={i} className="result-card glass-premium">
                                        <div className="result-value">{result.value}</div>
                                        <div className="result-metric">{result.metric}</div>
                                        <div className="result-description">{result.description.es}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </section>
                )}

                {/* Content Section */}
                <section className="project-content section">
                    <div className="container">
                        <div className="content-wrapper">
                            <div
                                className="markdown-content"
                                dangerouslySetInnerHTML={{ __html: sanitizeHtml(project.longDescription.es.replace(/\n/g, '<br/>')) }}
                            />
                        </div>
                    </div>
                </section>

                {/* Technologies Section */}
                {project.technologies && project.technologies.length > 0 && (
                    <section className="project-technologies section">
                        <div className="container">
                            <h2 className="section-title">Tecnologías Utilizadas</h2>
                            <div className="tech-grid">
                                {project.technologies.map((tech: string, i: number) => (
                                    <div key={i} className="tech-item glass-premium">
                                        {tech}
                                    </div>
                                ))}
                            </div>
                        </div>
                    </section>
                )}

                {/* Gallery Section */}
                {project.images.gallery.length > 0 && (
                    <section className="project-gallery section">
                        <div className="container">
                            <h2 className="section-title">Galería del Proyecto</h2>
                            <div className="gallery-grid">
                                {project.images.gallery.map((image: string, i: number) => (
                                    <div key={i} className="gallery-item">
                                        <img src={image} alt={`${project.title.es} - Imagen ${i + 1}`} />
                                    </div>
                                ))}
                            </div>
                        </div>
                    </section>
                )}

                {/* CTA Section */}
                <section className="project-cta section">
                    <div className="container">
                        <div className="cta-card glass-premium">
                            <h2>¿Quieres resultados similares?</h2>
                            <p>Hablemos sobre cómo puedo ayudarte a alcanzar tus objetivos de SEO y desarrollo web.</p>
                            <Link href="/#contact" className="btn btn-primary btn-large">
                                Contactar Ahora →
                            </Link>
                        </div>
                    </div>
                </section>
            </main>
        </>
    );
}
